mapper.select:
select 
from dispatch_task_definitions
where tenant_id = #{tenantId} and definition_id = #{definitionId}

select 
from dispatch_task_definitions
where tenant_id = #{tenantId}

  and status = #{status}

order by source_system asc, task_type asc
limit #{limit}

select 
from dispatch_event_task_mappings
where tenant_id = #{tenantId} and mapping_id = #{mappingId}

select 
from dispatch_event_task_mappings
where tenant_id = #{tenantId}

  and upper(source_system) = upper(#{sourceSystem})


  and is_active = #{active}

order by source_system asc, priority asc, updated_at desc
limit #{limit}

select 
from agent_assignment_profiles
where tenant_id = #{tenantId} and profile_code = #{profileCode}

select 
from agent_assignment_profiles
where tenant_id = #{tenantId}

  and (agent_type = #{agentType} or agent_type = 'ANY')


  and is_active = #{active}

order by profile_code asc
limit #{limit}

select 
from agent_capability_catalog
where tenant_id = #{tenantId} and capability_code = #{capabilityCode}

select 
from agent_capability_catalog
where tenant_id = #{tenantId}

  and status = #{status}


  and task_definition_id = #{taskDefinitionId}

order by capability_code asc
limit #{limit}

select 
from assignment_profile_capability_bindings
where tenant_id = #{tenantId} and profile_code = #{profileCode} and capability_code = #{capabilityCode}

select 
from assignment_profile_capability_bindings
where tenant_id = #{tenantId} and profile_code = #{profileCode}

  and is_active = #{active}

order by priority desc, capability_code asc

select 
from dispatch_policies
where tenant_id = #{tenantId} and policy_code = #{policyCode}

select 
from dispatch_policies
where tenant_id = #{tenantId}

  and status = #{status}

order by policy_code asc
limit #{limit}

select 
from dispatch_policy_scopes
where tenant_id = #{tenantId} and policy_code = #{policyCode}

  and is_active = #{active}

order by priority_order desc, source_system asc, task_type asc

select 
from dispatch_policy_required_capabilities
where tenant_id = #{tenantId} and policy_code = #{policyCode}

  and is_blocking = #{blocking}

order by priority desc, capability_code asc

select 
from dispatch_policy_required_runtime_features
where tenant_id = #{tenantId} and policy_code = #{policyCode}

  and is_blocking = #{blocking}

order by priority desc, feature_code asc

select 
from dispatch_policy_quality_rules
where tenant_id = #{tenantId} and policy_code = #{policyCode}

  and is_blocking = #{blocking}

order by is_blocking desc, metric_name asc

select 
from supply_profiles
where tenant_id = #{tenantId} and supply_profile_id = #{supplyProfileId}

select 
from supply_profiles
where tenant_id = #{tenantId} and profile_code = #{profileCode}

select 
from supply_profiles
where tenant_id = #{tenantId}

  and agent_id = #{agentId}


  and runtime_binding_id = #{runtimeBindingId}


  and status = #{status}

order by profile_code asc
limit #{limit}

select 
from runtime_resources
where tenant_id = #{tenantId} and runtime_id = #{runtimeId}

select 
from runtime_resources
where tenant_id = #{tenantId}

  and status = #{status}


  and trust_status = #{trustStatus}

order by runtime_code asc
limit #{limit}

select 
from agent_runtime_bindings
where binding_id = #{bindingId}

select 
from agent_runtime_bindings
where agent_id = #{agentId}

  and binding_status = #{status}

order by updated_at desc

select 
from agent_runtime_bindings
where tenant_id = #{tenantId}

  and runtime_id = #{runtimeId}


  and binding_status = #{status}

order by updated_at desc
limit #{limit}

select 
from runtime_feature_catalog
where tenant_id = #{tenantId} and feature_code = #{featureCode}

select 
from runtime_feature_catalog
where tenant_id = #{tenantId}

  and status = #{status}

order by category asc, feature_code asc
limit #{limit}

select 
from agent_runtime_feature_trust
where trust_id = #{trustId}

select 
from agent_capability_assignments
where assignment_id = #{assignmentId}

select 
from agent_capability_assignments
where agent_id = #{agentId} and capability_code = #{capabilityCode}

select  from agent_quality_metrics_daily
where tenant_id = #{tenantId}
and agent_id = #{agentId}
order by metric_date desc limit #{limit}

select  from agent_quality_metrics_window
where tenant_id = #{tenantId}
and agent_id = #{agentId}
and metric_window = #{metricWindow}
order by updated_at desc limit #{limit}

select  from runtime_quality_metrics_daily
where tenant_id = #{tenantId}
and runtime_id = #{runtimeId}
order by metric_date desc limit #{limit}

select  from supply_profile_quality_snapshot
where tenant_id = #{tenantId} and profile_code = #{profileCode}
and metric_window = #{metricWindow}
order by calculated_at desc limit 1

select  from supply_profile_quality_snapshot
where tenant_id = #{tenantId}
and agent_id = #{agentId}
and runtime_id = #{runtimeId}
and metric_window = #{metricWindow}
order by calculated_at desc limit #{limit}

select 
from agent_assignment_profile_policy_bindings
where tenant_id = #{tenantId} and profile_code = #{profileCode} and policy_code = #{policyCode}

select 
from agent_assignment_profile_policy_bindings
where tenant_id = #{tenantId}
  and profile_code = #{profileCode}

  and is_active = #{active}

order by priority desc, policy_code asc

select 
from agent_qualifications
where qualification_id = #{qualificationId}
